import{_ as o,o as t,c as d,ae as c}from"./chunks/framework.C7FLYIpo.js";const h=JSON.parse('{"title":"세션 도구","description":"크로스 세션 상태, 회상, 메시징, 서브 에이전트 오케스트레이션을 위한 에이전트 도구","frontmatter":{"title":"세션 도구","description":"크로스 세션 상태, 회상, 메시징, 서브 에이전트 오케스트레이션을 위한 에이전트 도구"},"headers":[],"relativePath":"concepts/session-tool.md","filePath":"concepts/session-tool.md","lastUpdated":null}'),a={name:"concepts/session-tool.md"};function s(l,e,i,n,r,p){return t(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="세션-도구" tabindex="-1">세션 도구 <a class="header-anchor" href="#세션-도구" aria-label="Permalink to &quot;세션 도구&quot;">​</a></h1><p>OpenClaw는 에이전트에게 세션 간 작업, 상태 검사, 서브 에이전트 오케스트레이션을 위한 도구를 제공합니다.</p><h2 id="사용-가능한-도구" tabindex="-1">사용 가능한 도구 <a class="header-anchor" href="#사용-가능한-도구" aria-label="Permalink to &quot;사용 가능한 도구&quot;">​</a></h2><table tabindex="0"><thead><tr><th>도구</th><th>기능</th></tr></thead><tbody><tr><td><code>sessions_list</code></td><td>선택적 필터 (kind, recency)로 세션 목록 조회</td></tr><tr><td><code>sessions_history</code></td><td>특정 세션의 트랜스크립트 읽기</td></tr><tr><td><code>sessions_send</code></td><td>다른 세션에 메시지 전송하고 선택적으로 대기</td></tr><tr><td><code>sessions_spawn</code></td><td>백그라운드 작업을 위한 격리된 서브 에이전트 세션 생성</td></tr><tr><td><code>sessions_yield</code></td><td>현재 턴을 종료하고 후속 서브 에이전트 결과를 기다림</td></tr><tr><td><code>subagents</code></td><td>이 세션에 대해 생성된 서브 에이전트 목록, 조종 또는 종료</td></tr><tr><td><code>session_status</code></td><td><code>/status</code> 스타일 카드를 표시하고 선택적으로 세션별 모델 오버라이드를 설정</td></tr></tbody></table><h2 id="세션-목록-및-읽기" tabindex="-1">세션 목록 및 읽기 <a class="header-anchor" href="#세션-목록-및-읽기" aria-label="Permalink to &quot;세션 목록 및 읽기&quot;">​</a></h2><p><code>sessions_list</code>는 키, 종류, 채널, 모델, 토큰 수, 타임스탬프와 함께 세션을 반환합니다. 종류 (<code>main</code>, <code>group</code>, <code>cron</code>, <code>hook</code>, <code>node</code>) 또는 최근성 (<code>activeMinutes</code>)으로 필터링하십시오.</p><p><code>sessions_history</code>는 특정 세션의 대화 트랜스크립트를 가져옵니다. 기본적으로 도구 결과는 제외됩니다 -- <code>includeTools: true</code>를 전달하면 볼 수 있습니다. 반환된 뷰는 의도적으로 제한되고 안전하게 필터링됩니다:</p><ul><li>어시스턴트 텍스트는 회상 전에 정규화됩니다: <ul><li>thinking 태그 제거됨</li><li><code>&amp;lt;relevant-memories&amp;gt;</code> / <code>&amp;lt;relevant_memories&amp;gt;</code> 스캐폴딩 블록 제거됨</li><li><code>&amp;lt;tool_call&amp;gt;...&amp;lt;/tool_call&amp;gt;</code>, <code>&amp;lt;function_call&amp;gt;...&amp;lt;/function_call&amp;gt;</code>, <code>&amp;lt;tool_calls&amp;gt;...&amp;lt;/tool_calls&amp;gt;</code>, <code>&amp;lt;function_calls&amp;gt;...&amp;lt;/function_calls&amp;gt;</code>와 같은 일반 텍스트 도구 호출 XML 페이로드 블록 제거됨 (깔끔하게 닫히지 않은 잘린 페이로드 포함)</li><li><code>[Tool Call: ...]</code>, <code>[Tool Result ...]</code>, <code>[Historical context ...]</code>와 같은 다운그레이드된 도구 호출/결과 스캐폴딩 제거됨</li><li><code>&lt;|assistant|&gt;</code>, 기타 ASCII <code>&lt;|...|&gt;</code> 토큰, 전각 <code>&lt;｜...｜&gt;</code> 변형과 같은 유출된 모델 제어 토큰 제거됨</li><li><code>&amp;lt;invoke ...&amp;gt;</code> / <code>&amp;lt;/minimax:tool_call&amp;gt;</code>와 같은 잘못된 형식의 MiniMax 도구 호출 XML 제거됨</li></ul></li><li>자격 증명/토큰 형태의 텍스트는 반환 전에 교정됩니다</li><li>긴 텍스트 블록은 잘립니다</li><li>매우 큰 히스토리는 오래된 행을 삭제하거나 과도한 크기의 행을 <code>[sessions_history omitted: message too large]</code>로 대체할 수 있습니다</li><li>도구는 <code>truncated</code>, <code>droppedMessages</code>, <code>contentTruncated</code>, <code>contentRedacted</code>, <code>bytes</code>와 같은 요약 플래그를 보고합니다</li></ul><p>두 도구 모두 <strong>세션 키</strong> (예: <code>&quot;main&quot;</code>) 또는 이전 목록 호출의 <strong>세션 ID</strong>를 허용합니다.</p><p>정확한 바이트 단위 트랜스크립트가 필요한 경우, <code>sessions_history</code>를 원시 덤프로 처리하는 대신 디스크의 트랜스크립트 파일을 직접 검사하십시오.</p><h2 id="크로스-세션-메시지-전송" tabindex="-1">크로스 세션 메시지 전송 <a class="header-anchor" href="#크로스-세션-메시지-전송" aria-label="Permalink to &quot;크로스 세션 메시지 전송&quot;">​</a></h2><p><code>sessions_send</code>는 다른 세션에 메시지를 전달하고 선택적으로 응답을 기다립니다:</p><ul><li><strong>Fire-and-forget:</strong> <code>timeoutSeconds: 0</code>을 설정하면 즉시 큐에 넣고 반환합니다.</li><li><strong>응답 대기:</strong> 타임아웃을 설정하고 응답을 인라인으로 받습니다.</li></ul><p>대상이 응답한 후, OpenClaw는 에이전트가 번갈아 메시지를 교환하는 <strong>응답 루프</strong>를 실행할 수 있습니다 (최대 5턴). 대상 에이전트는 <code>REPLY_SKIP</code>을 응답하여 일찍 중단할 수 있습니다.</p><h2 id="상태-및-오케스트레이션-도우미" tabindex="-1">상태 및 오케스트레이션 도우미 <a class="header-anchor" href="#상태-및-오케스트레이션-도우미" aria-label="Permalink to &quot;상태 및 오케스트레이션 도우미&quot;">​</a></h2><p><code>session_status</code>는 현재 또는 다른 가시적 세션을 위한 가벼운 <code>/status</code> 상당 도구입니다. 사용량, 시간, 모델/런타임 상태, 존재 시 연결된 백그라운드 태스크 컨텍스트를 보고합니다. <code>/status</code>와 마찬가지로, 최신 트랜스크립트 사용량 항목에서 희박한 토큰/캐시 카운터를 백필할 수 있으며, <code>model=default</code>는 세션별 오버라이드를 지웁니다.</p><p><code>sessions_yield</code>는 현재 턴을 의도적으로 종료하여 다음 메시지가 대기 중인 후속 이벤트가 될 수 있도록 합니다. 폴링 루프를 구축하는 대신 완료 결과가 다음 메시지로 도착하기를 원할 때 서브 에이전트를 생성한 후 사용하십시오.</p><p><code>subagents</code>는 이미 생성된 OpenClaw 서브 에이전트를 위한 컨트롤 플레인 도우미입니다. 다음을 지원합니다:</p><ul><li><code>action: &quot;list&quot;</code> 활성/최근 실행 검사</li><li><code>action: &quot;steer&quot;</code> 실행 중인 자식에게 후속 안내 전송</li><li><code>action: &quot;kill&quot;</code> 하나의 자식 또는 <code>all</code> 중단</li></ul><h2 id="서브-에이전트-생성" tabindex="-1">서브 에이전트 생성 <a class="header-anchor" href="#서브-에이전트-생성" aria-label="Permalink to &quot;서브 에이전트 생성&quot;">​</a></h2><p><code>sessions_spawn</code>은 백그라운드 태스크를 위한 격리된 세션을 생성합니다. 항상 비차단적입니다 -- 즉시 <code>runId</code>와 <code>childSessionKey</code>를 반환합니다.</p><p>주요 옵션:</p><ul><li><code>runtime: &quot;subagent&quot;</code> (기본값) 또는 외부 하네스 에이전트에는 <code>&quot;acp&quot;</code>.</li><li>자식 세션에 대한 <code>model</code> 및 <code>thinking</code> 오버라이드.</li><li><code>thread: true</code> 생성을 채팅 스레드 (Discord, Slack 등)에 바인딩.</li><li><code>sandbox: &quot;require&quot;</code> 자식에게 샌드박싱 강제.</li></ul><p>기본 리프 서브 에이전트는 세션 도구를 받지 않습니다. <code>maxSpawnDepth &gt;= 2</code>인 경우, 깊이-1 오케스트레이터 서브 에이전트는 자체 자식을 관리할 수 있도록 <code>sessions_spawn</code>, <code>subagents</code>, <code>sessions_list</code>, <code>sessions_history</code>를 추가로 받습니다. 리프 실행은 여전히 재귀 오케스트레이션 도구를 받지 않습니다.</p><p>완료 후, 공지 단계가 요청자의 채널에 결과를 게시합니다. 완료 전달은 가능한 경우 바인딩된 스레드/토픽 라우팅을 보존하며, 완료 출처가 채널만 식별하는 경우 OpenClaw는 직접 전달을 위해 요청자 세션의 저장된 경로 (<code>lastChannel</code> / <code>lastTo</code>)를 재사용할 수 있습니다.</p><p>ACP별 동작은 <a href="/openclaw-docs-ko/tools/acp-agents">ACP 에이전트</a>를 참조하십시오.</p><h2 id="가시성" tabindex="-1">가시성 <a class="header-anchor" href="#가시성" aria-label="Permalink to &quot;가시성&quot;">​</a></h2><p>세션 도구는 에이전트가 볼 수 있는 것을 제한하는 범위로 설정됩니다:</p><table tabindex="0"><thead><tr><th>수준</th><th>범위</th></tr></thead><tbody><tr><td><code>self</code></td><td>현재 세션만</td></tr><tr><td><code>tree</code></td><td>현재 세션 + 생성된 서브 에이전트</td></tr><tr><td><code>agent</code></td><td>이 에이전트의 모든 세션</td></tr><tr><td><code>all</code></td><td>모든 세션 (구성된 경우 크로스 에이전트)</td></tr></tbody></table><p>기본값은 <code>tree</code>입니다. 샌드박싱된 세션은 구성에 관계없이 <code>tree</code>로 제한됩니다.</p><h2 id="추가-읽기" tabindex="-1">추가 읽기 <a class="header-anchor" href="#추가-읽기" aria-label="Permalink to &quot;추가 읽기&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/session">세션 관리</a> -- 라우팅, 라이프사이클, 유지 관리</li><li><a href="/openclaw-docs-ko/tools/acp-agents">ACP 에이전트</a> -- 외부 하네스 생성</li><li><a href="/openclaw-docs-ko/concepts/multi-agent">멀티 에이전트</a> -- 멀티 에이전트 아키텍처</li><li><a href="/openclaw-docs-ko/gateway/configuration">게이트웨이 구성</a> -- 세션 도구 구성 설정</li></ul>',32)])])}const m=o(a,[["render",s]]);export{h as __pageData,m as default};
